code.cpp:
int highestOccurring(vector<int>& arr){
    unordered_map<int,int> mp;
    for(int x : arr) mp[x]++;
    int maxFreq = 0, ans = arr[0];
    for(auto& p : mp){
        if(p.second > maxFreq){
            maxFreq = p.second;
            ans = p.first;
        }
    }
    return ans;
}

