        boolean swapped = false;
        for(int j=0;j<n-1-i;j++){
            if(arr[j] > arr[j+1]){
                int t = arr[j]; arr[j] = arr[j+1]; arr[j+1] = t;
                swapped = true;
            }
        }
        if(!swapped) break;
    }
}

