        while(j>=low && arr[j]>pivot) j--;
        if(i < j){ int t=arr[i]; arr[i]=arr[j]; arr[j]=t; }
    }
    int t=arr[low]; arr[low]=arr[j]; arr[j]=t;
    return j;
}
