vector<int> findMissRep(vector<int>& a){
    long n=a.size(),S=0,S2=0;
    for(int x:a){S+=x;S2+=(long)x*x;}
    long sn=n*(n+1)/2, s2n=n*(n+1)*(2*n+1)/6;
    long d1=S-sn, d2=S2-s2n;
    long sum=d2/d1;
    int rep=(int)(d1+sum)/2, miss=(int)(sum-d1)/2;
    return {rep,miss};
}

