int nthRoot(int n,int m){
    int l=1,r=m;
    while(l<=r){
        int mid=l+(r-l)/2;
        long val=1;
        for(int i=0;i<n;i++){val*=mid;if(val>m) break;}
        if(val==m) return mid;
        else if(val<m) l=mid+1;
        else r=mid-1;
    }
    return -1;
}

