double findMedian(vector<int>& a,vector<int>& b){
    if(a.size()>b.size()) return findMedian(b,a);
    int n1=a.size(),n2=b.size(),l=0,r=n1;
    while(l<=r){
        int c1=l+(r-l)/2,c2=(n1+n2+1)/2-c1;
        int l1=c1>0?a[c1-1]:INT_MIN;
        int l2=c2>0?b[c2-1]:INT_MIN;
        int r1=c1<n1?a[c1]:INT_MAX;
        int r2=c2<n2?b[c2]:INT_MAX;
        if(l1<=r2&&l2<=r1){
            if((n1+n2)%2) return max(l1,l2);
            return (max(l1,l2)+min(r1,r2))/2.0;
        }
        if(l1>r2) r=c1-1;
        else l=c1+1;
    }
    return 0;
}

