vector<int> findPeak(vector<vector<int>>& m){
    int l=0,r=m[0].size()-1;
    while(l<=r){
        int mid=l+(r-l)/2;
        int maxRow=0;
        for(int i=1;i<m.size();i++)
            if(m[i][mid]>m[maxRow][mid]) maxRow=i;
        bool leftOk=mid==0||m[maxRow][mid]>m[maxRow][mid-1];
        bool rightOk=mid==m[0].size()-1||m[maxRow][mid]>m[maxRow][mid+1];
        if(leftOk&&rightOk) return {maxRow,mid};
        else if(!leftOk) r=mid-1;
        else l=mid+1;
    }
    return {-1,-1};
}

