int matrixMedian(vector<vector<int>>& m){
    int l=INT_MAX,r=INT_MIN;
    for(auto& row:m){l=min(l,row[0]);r=max(r,row.back());}
    int target=(m.size()*m[0].size())/2;
    while(l<=r){
        int mid=l+(r-l)/2;
        int cnt=0;
        for(auto& row:m)
            cnt+=upper_bound(row.begin(),row.end(),mid)-row.begin();
        if(cnt<=target) l=mid+1;
        else r=mid-1;
    }
    return l;
}

