static int matrixMedian(int[][] m){
    int l=Integer.MAX_VALUE,r=0;
    for(int[] row:m){l=Math.min(l,row[0]);r=Math.max(r,row[row.length-1]);}
    int target=(m.length*m[0].length)/2;
    while(l<=r){
        int mid=l+(r-l)/2;
        int cnt=0;
        for(int[] row:m){
            int lo=0,hi=row.length;
            while(lo<hi){int mm=lo+(hi-lo)/2;if(row[mm]<=mid)lo=mm+1;else hi=mm;}
            cnt+=lo;
        }
        if(cnt<=target) l=mid+1;
        else r=mid-1;
    }
    return l;
}

