Node* addOne(Node* head){
    // Reverse
    Node *prev=nullptr,*cur=head;
    while(cur){Node* n=cur->next;cur->next=prev;prev=cur;cur=n;}
    head=prev;
    // Add one
    int carry=1;
    cur=head;
    while(cur&&carry){
        int s=cur->data+carry;
        cur->data=s%10;
        carry=s/10;
        if(!cur->next&&carry) cur->next=new Node(0);
        cur=cur->next;
    }
    // Reverse back
    prev=nullptr;cur=head;
    while(cur){Node* n=cur->next;cur->next=prev;prev=cur;cur=n;}
    return prev;
}

