    vector<pair<int,int>> res;
    DNode *l=head,*r=head;
    while(r->next) r=r->next;
    while(l!=r&&l->prev!=r){
        int s=l->data+r->data;
        if(s==sum){res.push_back({l->data,r->data});l=l->next;r=r->prev;}
        else if(s<sum) l=l->next;
        else r=r->prev;
    }
    return res;
}

