code.cpp:
Node* rotateRight(Node* head,int k){
    if(!head||!head->next||k==0) return head;
    int len=1;
    Node* tail=head;
    while(tail->next){tail=tail->next;len++;}
    k%=len;
    if(k==0) return head;
    tail->next=head;
    Node* newTail=head;
    for(int i=0;i<len-k-1;i++) newTail=newTail->next;
    head=newTail->next;
    newTail->next=nullptr;
    return head;
}

