Node* copyRandomList(Node* head){
    if(!head) return nullptr;
    // Step 1: Insert clones
    Node* cur=head;
    while(cur){
        Node* clone=new Node(cur->val);
        clone->next=cur->next;
        cur->next=clone;
        cur=clone->next;
    }
    // Step 2: Set random
    cur=head;
    while(cur){
        if(cur->random) cur->next->random=cur->random->next;
        cur=cur->next->next;
    }
    // Step 3: Separate
    cur=head;
    Node* cloneHead=head->next;
    while(cur){
        Node* clone=cur->next;
        cur->next=clone->next;
        clone->next=clone->next?clone->next->next:nullptr;
        cur=cur->next;
    }
    return cloneHead;
}

