static Node copyRandomList(Node head){
    if(head==null) return null;
    Node cur=head;
    while(cur!=null){
        Node clone=new Node(cur.val);
        clone.next=cur.next;cur.next=clone;cur=clone.next;
    }
    cur=head;
    while(cur!=null){
        if(cur.random!=null) cur.next.random=cur.random.next;
        cur=cur.next.next;
    }
    cur=head;Node cloneHead=head.next;
    while(cur!=null){
        Node clone=cur.next;
        cur.next=clone.next;
        clone.next=clone.next!=null?clone.next.next:null;
        cur=cur.next;
    }
    return cloneHead;
}

