// Subsequence patterns:
// 1. Include/Exclude: pick or skip each element
// 2. For loops: iterate choices at each level
// 3. Bit masking: use 0 to 2^n-1
void subseq(vector<int>&a,int i,vector<int>&cur){
    if(i==a.size()){/* process cur */return;}
    cur.push_back(a[i]);
    subseq(a,i+1,cur); // include
    cur.pop_back();
    subseq(a,i+1,cur); // exclude
}

