    int dx[]={1,0,0,-1}; int dy[]={0,-1,1,0};
    char dc[]={'D','L','R','U'};
    for(int k=0;k<4;k++){
        int ni=i+dx[k],nj=j+dy[k];
        if(ni>=0&&ni<n&&nj>=0&&nj<n&&m[ni][nj]==1&&!vis[ni][nj]){
            vis[ni][nj]=true;
            solve(m,ni,nj,n,path+dc[k],res,vis);
            vis[ni][nj]=false;
        }
    }
}

