    def solve(i,j,path):
        if i==n-1 and j==n-1: res.append(path);return
        for di,dj,d in [(1,0,'D'),(0,-1,'L'),(0,1,'R'),(-1,0,'U')]:
            ni,nj=i+di,j+dj
            if 0<=ni<n and 0<=nj<n and m[ni][nj]==1 and not vis[ni][nj]:
