int divide(int dividend,int divisor){
    if(dividend==INT_MIN&&divisor==-1) return INT_MAX;
    long a=abs((long)dividend),b=abs((long)divisor);
    int res=0;
    while(a>=b){
        int shift=0;
        while(a>=(b<<(shift+1))) shift++;
        res+=(1<<shift);
        a-=(b<<shift);
    }
    return (dividend>0)==(divisor>0)?res:-res;
}

