def infix_to_postfix(s):
    prec={'+':1,'-':1,'*':2,'/':2,'^':3}
    res,st=[],[]
    for c in s:
        if c.isalnum():res.append(c)
        elif c=='(':st.append(c)
        elif c==')':
            while st[-1]!='(':res.append(st.pop())
            st.pop()
        else:
            while st and st[-1]!='(' and prec.get(st[-1],0)>=prec.get(c,0):res.append(st.pop())
            st.append(c)
    while st:res.append(st.pop())
    return ''.join(res)

