int sumSubarrayMins(vector<int>&a){
    int n=a.size(),MOD=1e9+7;
    stack<int>st;
    long res=0;
    for(int i=0;i<=n;i++){
        while(!st.empty()&&(i==n||a[st.top()]>=a[i])){
            int mid=st.top();st.pop();
            int left=st.empty()?-1:st.top();
            res=(res+(long)a[mid]*(mid-left)*(i-mid))%MOD;
        }
        st.push(i);
    }
    return res;
}

