vector<int> asteroidCollision(vector<int>&a){
    stack<int>st;
    for(int x:a){
        bool alive=true;
        while(alive&&x<0&&!st.empty()&&st.top()>0){
            if(st.top()<-x)st.pop();
            else if(st.top()==-x){st.pop();alive=false;}
            else alive=false;
        }
        if(alive)st.push(x);
    }
    vector<int>res(st.size());
    for(int i=st.size()-1;i>=0;i--){res[i]=st.top();st.pop();}
    return res;
}

