long long subArrayRanges(vector<int>&a){
    int n=a.size();
    long long sumMax=0,sumMin=0;
    stack<int>st;
    // Sum of subarray mins
    for(int i=0;i<=n;i++){
        while(!st.empty()&&(i==n||a[st.top()]>=a[i])){
            int m=st.top();st.pop();
            int l=st.empty()?-1:st.top();
            sumMin+=(long long)a[m]*(m-l)*(i-m);
        }
        st.push(i);
    }
    while(!st.empty())st.pop();
    // Sum of subarray maxs
    for(int i=0;i<=n;i++){
        while(!st.empty()&&(i==n||a[st.top()]<=a[i])){
            int m=st.top();st.pop();
            int l=st.empty()?-1:st.top();
            sumMax+=(long long)a[m]*(m-l)*(i-m);
        }
        st.push(i);
    }
    return sumMax-sumMin;
}

