def sub_array_ranges(a):
    n=len(a)
    def helper(comp):
        st,res=[],0
        for i in range(n+1):
            while st and (i==n or comp(a[st[-1]],a[i])):
                m=st.pop();l=st[-1] if st else -1
                res+=a[m]*(m-l)*(i-m)
            st.append(i)
        return res
    return helper(lambda a,b:a<=b)-helper(lambda a,b:a>=b)

