string removeKdigits(string num,int k){
    string st;
    for(char c:num){
        while(k>0&&!st.empty()&&st.back()>c){st.pop_back();k--;}
        st.push_back(c);
    }
    while(k-->0)st.pop_back();
    int i=0;
    while(i<st.size()&&st[i]=='0')i++;
    string res=st.substr(i);
    return res.empty()?"0":res;
}

