int largestRectangle(vector<int>&h){
    int n=h.size(),mx=0;
    stack<int>st;
    for(int i=0;i<=n;i++){
        while(!st.empty()&&(i==n||h[st.top()]>=h[i])){
            int ht=h[st.top()];st.pop();
            int w=st.empty()?i:i-st.top()-1;
