// LFU Cache using min frequency tracking
// HashMap for key->value, key->freq
// FreqMap: freq -> list of keys (ordered by recency)
class LFUCache{
    int cap,minFreq;
    unordered_map<int,pair<int,int>>kv; // key->(val,freq)
    unordered_map<int,list<int>>freq; // freq->keys
    unordered_map<int,list<int>::iterator>pos;
public:
    LFUCache(int c):cap(c),minFreq(0){}
    int get(int key){
        if(!kv.count(key))return -1;
        touch(key);return kv[key].first;
    }
    void put(int key,int val){
        if(cap<=0)return;
        if(kv.count(key)){kv[key].first=val;touch(key);return;}
        if(kv.size()==cap){
            int evict=freq[minFreq].back();
            freq[minFreq].pop_back();pos.erase(evict);kv.erase(evict);
        }
        kv[key]={val,1};minFreq=1;
        freq[1].push_front(key);pos[key]=freq[1].begin();
    }
    void touch(int key){
        int f=kv[key].second;
        freq[f].erase(pos[key]);
        if(freq[f].empty()&&f==minFreq)minFreq++;
        kv[key].second++;
        freq[f+1].push_front(key);pos[key]=freq[f+1].begin();
    }
};

