from collections import defaultdict,OrderedDict
class LFUCache:
    def __init__(self,cap):
        self.cap,self.min_freq=cap,0
        self.key_val,self.key_freq={},{}
        self.freq_keys=defaultdict(OrderedDict)
    def get(self,key):
        if key not in self.key_val:return -1
        self._touch(key)
        return self.key_val[key]
    def put(self,key,val):
        if self.cap<=0:return
        if key in self.key_val:
            self.key_val[key]=val;self._touch(key);return
        if len(self.key_val)>=self.cap:
            k,_=self.freq_keys[self.min_freq].popitem(last=False)
            del self.key_val[k];del self.key_freq[k]
        self.key_val[key]=val;self.key_freq[key]=1
        self.freq_keys[1][key]=None;self.min_freq=1
    def _touch(self,key):
        f=self.key_freq[key]
        del self.freq_keys[f][key]
        if not self.freq_keys[f] and f==self.min_freq:self.min_freq+=1
        self.key_freq[key]=f+1
        self.freq_keys[f+1][key]=None

