class MinHeap{
    vector<int>h;
    void siftUp(int i){while(i>0&&h[i]<h[(i-1)/2]){swap(h[i],h[(i-1)/2]);i=(i-1)/2;}}
    void siftDown(int i){int n=h.size();while(2*i+1<n){int j=2*i+1;if(j+1<n&&h[j+1]<h[j])j++;if(h[i]<=h[j])break;swap(h[i],h[j]);i=j;}}
public:
    void push(int x){h.push_back(x);siftUp(h.size()-1);}
    int pop(){int v=h[0];h[0]=h.back();h.pop_back();siftDown(0);return v;}
    int top(){return h[0];}
};

