void convertToMaxHeap(vector<int>&a){
    int n=a.size();
    for(int i=n/2-1;i>=0;i--){
        int j=i;
        while(2*j+1<n){
            int c=2*j+1;
            if(c+1<n&&a[c+1]>a[c])c++;
            if(a[j]>=a[c])break;
            swap(a[j],a[c]);j=c;
        }
    }
}

