bool isNStraightHand(vector<int>&h,int gs){
    if(h.size()%gs!=0)return false;
    map<int,int>mp;
    for(int x:h)mp[x]++;
    for(auto&[k,v]:mp){
        if(v>0){
            int cnt=v;
            for(int i=0;i<gs;i++){
                if(mp[k+i]<cnt)return false;
                mp[k+i]-=cnt;
            }
        }
    }
    return true;
}

