static boolean isNStraightHand(int[]h,int gs){
    if(h.length%gs!=0)return false;
    TreeMap<Integer,Integer>mp=new TreeMap<>();
    for(int x:h)mp.merge(x,1,Integer::sum);
    while(!mp.isEmpty()){
        int first=mp.firstKey();
        for(int i=0;i<gs;i++){
            if(!mp.containsKey(first+i))return false;
            mp.merge(first+i,-1,Integer::sum);
            if(mp.get(first+i)==0)mp.remove(first+i);
        }
    }
    return true;
}

