vector<int> maxSumComb(vector<int>&a,vector<int>&b,int k){
    sort(a.rbegin(),a.rend());sort(b.rbegin(),b.rend());
    priority_queue<pair<int,pair<int,int>>>pq;
    set<pair<int,int>>vis;
    pq.push({a[0]+b[0],{0,0}});vis.insert({0,0});
    vector<int>res;
    while(k--){
        auto[s,p]=pq.top();pq.pop();
        auto[i,j]=p;res.push_back(s);
        if(i+1<a.size()&&!vis.count({i+1,j})){pq.push({a[i+1]+b[j],{i+1,j}});vis.insert({i+1,j});}
        if(j+1<b.size()&&!vis.count({i,j+1})){pq.push({a[i]+b[j+1],{i,j+1}});vis.insert({i,j+1});}
    }
    return res;
}

