double fractionalKnapsack(int W,vector<pair<int,int>>&items){
    sort(items.begin(),items.end(),[](auto&a,auto&b){
        return (double)a.first/a.second>(double)b.first/b.second;
    });
    double res=0;
    for(auto&[v,w]:items){
        if(W>=w){res+=v;W-=w;}
        else{res+=(double)v/w*W;break;}
    }
    return res;
}

