pair<int,int> jobScheduling(vector<pair<int,int>>&jobs){
    sort(jobs.begin(),jobs.end(),[](auto&a,auto&b){return a.second>b.second;});
    int maxD=0;
    for(auto&j:jobs)maxD=max(maxD,j.first);
    vector<bool>slot(maxD+1,false);
    int cnt=0,profit=0;
    for(auto&[d,p]:jobs)
        for(int i=d;i>=1;i--)
            if(!slot[i]){slot[i]=true;cnt++;profit+=p;break;}
    return{cnt,profit};
}

