int lruPageFaults(vector<int>&pages,int k){
    deque<int>dq;
    unordered_set<int>st;
    int faults=0;
    for(int p:pages){
        if(!st.count(p)){
            faults++;
            if(dq.size()==k){st.erase(dq.back());dq.pop_back();}
        }else{
            dq.erase(find(dq.begin(),dq.end(),p));
        }
        dq.push_front(p);st.insert(p);
    }
    return faults;
}

