static int lruPageFaults(int[]pages,int k){
    LinkedHashSet<Integer>set=new LinkedHashSet<>();
    int faults=0;
    for(int p:pages){
        if(!set.contains(p)){
            faults++;
            if(set.size()==k){int first=set.iterator().next();set.remove(first);}
        }else set.remove(p);
        set.add(p);
    }
    return faults;
}

