void allTraversals(TreeNode*root){
    stack<pair<TreeNode*,int>>st;
    st.push({root,1});
    vector<int>pre,in,post;
    while(!st.empty()){
        auto[node,state]=st.top();st.pop();
        if(state==1){pre.push_back(node->val);st.push({node,2});if(node->left)st.push({node->left,1});}
        else if(state==2){in.push_back(node->val);st.push({node,3});if(node->right)st.push({node->right,1});}
        else post.push_back(node->val);
    }
}

