vector<vector<int>> levelOrder(TreeNode*r){
    vector<vector<int>>res;
    if(!r)return res;
    queue<TreeNode*>q;
    q.push(r);
    while(!q.empty()){
        int sz=q.size();vector<int>lv;
        while(sz--){auto n=q.front();q.pop();lv.push_back(n->val);
            if(n->left)q.push(n->left);if(n->right)q.push(n->right);}
        res.push_back(lv);
    }
    return res;
}

