static List<List<Integer>> levelOrder(TreeNode r){
    List<List<Integer>>res=new ArrayList<>();
    if(r==null)return res;
    Queue<TreeNode>q=new LinkedList<>();q.add(r);
    while(!q.isEmpty()){
        int sz=q.size();List<Integer>lv=new ArrayList<>();
        while(sz-->0){TreeNode n=q.poll();lv.add(n.val);
            if(n.left!=null)q.add(n.left);if(n.right!=null)q.add(n.right);}
        res.add(lv);
    }
    return res;
}

