vector<vector<int>> verticalTraversal(TreeNode*r){
    map<int,map<int,multiset<int>>>mp;
    queue<tuple<TreeNode*,int,int>>q;
    q.push({r,0,0});
    while(!q.empty()){
        auto[n,row,col]=q.front();q.pop();
        mp[col][row].insert(n->val);
        if(n->left)q.push({n->left,row+1,col-1});
        if(n->right)q.push({n->right,row+1,col+1});
    }
    vector<vector<int>>res;
    for(auto&[c,rows]:mp){vector<int>col;for(auto&[r,vals]:rows)for(int v:vals)col.push_back(v);res.push_back(col);}
    return res;
}

