int widthOfBinaryTree(TreeNode*r){
    int mx=0;
    queue<pair<TreeNode*,long long>>q;q.push({r,0});
    while(!q.empty()){
        int sz=q.size();long long mn=q.front().second;
        long long first,last;
        for(int i=0;i<sz;i++){
            auto[n,idx]=q.front();q.pop();
            idx-=mn;
            if(i==0)first=idx;if(i==sz-1)last=idx;
            if(n->left)q.push({n->left,2*idx+1});
            if(n->right)q.push({n->right,2*idx+2});
        }
        mx=max(mx,(int)(last-first+1));
    }
    return mx;
}

