vector<int> distanceK(TreeNode*r,TreeNode*t,int k){
    unordered_map<TreeNode*,TreeNode*>par;
    queue<TreeNode*>q;q.push(r);
    while(!q.empty()){
        auto n=q.front();q.pop();
        if(n->left){par[n->left]=n;q.push(n->left);}
        if(n->right){par[n->right]=n;q.push(n->right);}
    }
    unordered_set<TreeNode*>vis;vis.insert(t);
    q.push(t);
    while(k-->0){
        int sz=q.size();
        while(sz--){
            auto n=q.front();q.pop();
            if(n->left&&!vis.count(n->left)){vis.insert(n->left);q.push(n->left);}
            if(n->right&&!vis.count(n->right)){vis.insert(n->right);q.push(n->right);}
            if(par.count(n)&&!vis.count(par[n])){vis.insert(par[n]);q.push(par[n]);}
        }
    }
    vector<int>res;
    while(!q.empty()){res.push_back(q.front()->val);q.pop();}
    return res;
}

