from collections import deque
def distance_k(r,t,k):
    par={}
    q=deque([r])
    while q:
        n=q.popleft()
        if n.left:par[n.left]=n;q.append(n.left)
        if n.right:par[n.right]=n;q.append(n.right)
    vis={t};q=deque([t])
    while k:
        for _ in range(len(q)):
            n=q.popleft()
            for nb in [n.left,n.right,par.get(n)]:
                if nb and nb not in vis:vis.add(nb);q.append(nb)
        k-=1
    return [n.val for n in q]

