// 1. Inorder traversal of both BSTs
// 2. Merge two sorted arrays
// 3. Build balanced BST from merged array
vector<int> inorder(TreeNode*r){
    if(!r)return {};
    auto l=inorder(r->left);
    l.push_back(r->val);
    auto ri=inorder(r->right);
    l.insert(l.end(),ri.begin(),ri.end());
    return l;
}

