def merge_bst(r1,r2):
    def inorder(r):
        if not r:return []
        return inorder(r.left)+[r.val]+inorder(r.right)
    a,b=inorder(r1),inorder(r2)
    merged=sorted(a+b)
    def build(arr):
        if not arr:return None
        m=len(arr)//2
        r=TreeNode(arr[m])
        r.left=build(arr[:m]);r.right=build(arr[m+1:])
        return r
    return build(merged)

