void recoverTree(TreeNode*r){
    TreeNode*first=nullptr,*second=nullptr,*prev=nullptr;
    function<void(TreeNode*)>inorder=[&](TreeNode*n){
        if(!n)return;
        inorder(n->left);
        if(prev&&prev->val>n->val){
            if(!first)first=prev;
            second=n;
        }
        prev=n;
        inorder(n->right);
    };
    inorder(r);
    swap(first->val,second->val);
}

