Info solve(TreeNode*r){
    if(!r)return{0,INT_MAX,INT_MIN,true};
    auto l=solve(r->left),ri=solve(r->right);
    if(l.isBST&&ri.isBST&&l.mx<r->val&&r->val<ri.mn)
        return{l.size+ri.size+1,min(l.mn,r->val),max(ri.mx,r->val),true};
    return{max(l.size,ri.size),0,0,false};
}

