def largest_bst(r):
    def solve(n):
        if not n:return 0,float('inf'),float('-inf'),True
        ls,lmn,lmx,lb=solve(n.left)
        rs,rmn,rmx,rb=solve(n.right)
        if lb and rb and lmx<n.val<rmn:
            return ls+rs+1,min(lmn,n.val),max(rmx,n.val),True
        return max(ls,rs),0,0,False
    return solve(r)[0]

