// Without PQ: O(V^2) - check all vertices for minimum
// With PQ: O(E log V) - efficiently get minimum distance vertex
// PQ maintains vertices ordered by current shortest distance

int shortestPath(vector<vector<int>>&grid,vector<int>&src,vector<int>&dst){
    int m=grid.size(),n=grid[0].size();
    vector<vector<int>>dist(m,vector<int>(n,INT_MAX));
    dist[src[0]][src[1]]=0;
    queue<pair<int,int>>q;q.push({src[0],src[1]});
    int dx[]={0,0,1,-1},dy[]={1,-1,0,0};
    while(!q.empty()){
        auto[x,y]=q.front();q.pop();
        for(int d=0;d<4;d++){
            int nx=x+dx[d],ny=y+dy[d];
            if(nx>=0&&nx<m&&ny>=0&&ny<n&&grid[nx][ny]==1&&dist[x][y]+1<dist[nx][ny]){
                dist[nx][ny]=dist[x][y]+1;q.push({nx,ny});
            }
        }
    }
    return dist[dst[0]][dst[1]]==INT_MAX?-1:dist[dst[0]][dst[1]];
}

