// 1. Connects all V vertices with V-1 edges
// 2. Minimum total weight
// 3. No cycles
// Algorithms: Prim's (greedy, PQ) and Kruskal's (sort edges, Union-Find)

int primMST(int n,vector<vector<pair<int,int>>>&adj){
    vector<bool>inMST(n,false);
    priority_queue<pair<int,int>,vector<pair<int,int>>,greater<>>pq;
    pq.push({0,0});int cost=0;
    while(!pq.empty()){
        auto[w,u]=pq.top();pq.pop();
        if(inMST[u])continue;
        inMST[u]=true;cost+=w;
        for(auto[v,wt]:adj[u])if(!inMST[v])pq.push({wt,v});
    }
    return cost;
}

