class DSU{
    vector<int>par,rank;
public:
    DSU(int n):par(n),rank(n,0){iota(par.begin(),par.end(),0);}
    int find(int x){return par[x]==x?x:par[x]=find(par[x]);}
    void unite(int x,int y){
        x=find(x);y=find(y);
        if(x==y)return;
        if(rank[x]<rank[y])swap(x,y);
        par[y]=x;
        if(rank[x]==rank[y])rank[x]++;
    }
};

