int kruskalMST(int n,vector<vector<int>>&edges){
    sort(edges.begin(),edges.end(),[](auto&a,auto&b){return a[2]<b[2];});
    DSU dsu(n);int cost=0,cnt=0;
    for(auto&e:edges){
        if(dsu.find(e[0])!=dsu.find(e[1])){
            dsu.unite(e[0],e[1]);cost+=e[2];cnt++;
            if(cnt==n-1)break;
        }
    }
    return cost;
}

