import heapq
def swim_in_water(grid):
    n=len(grid);vis=[[False]*n for _ in range(n)]
    h=[(grid[0][0],0,0)];vis[0][0]=True
    while h:
        t,x,y=heapq.heappop(h)
        if x==n-1 and y==n-1:return t
        for dx,dy in[(0,1),(0,-1),(1,0),(-1,0)]:
            nx,ny=x+dx,y+dy
            if 0<=nx<n and 0<=ny<n and not vis[nx][ny]:
                vis[nx][ny]=True
                heapq.heappush(h,(max(t,grid[nx][ny]),nx,ny))
    return 0

