void dfs(int u,int par,int&timer,vector<vector<int>>&adj,vector<int>&disc,vector<int>&low,vector<pair<int,int>>&bridges){
    disc[u]=low[u]=timer++;
    for(int v:adj[u]){
        if(v==par)continue;
        if(disc[v]==-1){
            dfs(v,u,timer,adj,disc,low,bridges);
            low[u]=min(low[u],low[v]);
            if(low[v]>disc[u])bridges.push_back({u,v});
        }else low[u]=min(low[u],disc[v]);
    }
}

