int kosaraju(int n,vector<vector<int>>&adj){
    vector<bool>vis(n);stack<int>st;
    // Pass 1: fill stack with finish order
    function<void(int)>dfs1=[&](int u){vis[u]=true;for(int v:adj[u])if(!vis[v])dfs1(v);st.push(u);};
    for(int i=0;i<n;i++)if(!vis[i])dfs1(i);
    // Reverse graph
    vector<vector<int>>rev(n);
    for(int u=0;u<n;u++)for(int v:adj[u])rev[v].push_back(u);
    // Pass 2: DFS on reversed graph
    fill(vis.begin(),vis.end(),false);int cnt=0;
    function<void(int)>dfs2=[&](int u){vis[u]=true;for(int v:rev[u])if(!vis[v])dfs2(v);};
    while(!st.empty()){int u=st.top();st.pop();if(!vis[u]){cnt++;dfs2(u);}}
    return cnt;
}

code.python:
def kosaraju(n,adj):
    vis=set();order=[]
    def dfs1(u):
        vis.add(u)
        for v in adj[u]:
            if v not in vis:dfs1(v)
        order.append(u)
    for i in range(n):
        if i not in vis:dfs1(i)
    rev=[[] for _ in range(n)]
    for u in range(n):
        for v in adj[u]:rev[v].append(u)
    vis.clear();cnt=0
    def dfs2(u):
        vis.add(u)
        for v in rev[u]:
            if v not in vis:dfs2(v)
    for u in reversed(order):
        if u not in vis:cnt+=1;dfs2(u)
    return cnt

