int lcs(string a,string b){
    int m=a.size(),n=b.size();
    vector<int>prev(n+1,0),cur(n+1,0);
    for(int i=1;i<=m;i++){
        for(int j=1;j<=n;j++)
            cur[j]=a[i-1]==b[j-1]?prev[j-1]+1:max(prev[j],cur[j-1]);
