int longestStrChain(vector<string>&words){
    sort(words.begin(),words.end(),[](auto&a,auto&b){return a.size()<b.size();});
    unordered_map<string,int>dp;
    int mx=1;
    for(auto&w:words){
        dp[w]=1;
        for(int i=0;i<w.size();i++){
            string prev=w.substr(0,i)+w.substr(i+1);
