    for i in range(1,n):
        for j in range(i):
            if a[j]<a[i]:lis[i]=max(lis[i],lis[j]+1)
    for i in range(n-2,-1,-1):
        for j in range(n-1,i,-1):
            if a[j]<a[i]:lds[i]=max(lds[i],lds[j]+1)
    return max(lis[i]+lds[i]-1 for i in range(n))

