int findMaximumXOR(vector<int>&a){
    BitTrie*root=new BitTrie();
    for(int x:a)insert(root,x);
    int mx=0;
    for(int x:a){
        auto n=root;int cur=0;
        for(int i=31;i>=0;i--){
            int bit=(x>>i)&1;
            if(n->ch[1-bit]){cur|=(1<<i);n=n->ch[1-bit];}
            else n=n->ch[bit];
        }
        mx=max(mx,cur);
    }
    return mx;
}

