// Polynomial rolling hash:
// hash(s) = sum(s[i] * p^i) mod M
// Used in Rabin-Karp algorithm
long long polyHash(string s,long long p=31,long long M=1e9+9){
    long long h=0,pw=1;
    for(char c:s){h=(h+(c-'a'+1)*pw)%M;pw=pw*p%M;}
    return h;
}

