vector<int> rabinKarp(string text,string pattern){
    int n=text.size(),m=pattern.size();
    long long p=31,M=1e9+9;
    long long ph=0,th=0,pw=1;
    for(int i=0;i<m;i++){ph=(ph+(pattern[i]-'a'+1)*pw)%M;th=(th+(text[i]-'a'+1)*pw)%M;pw=pw*p%M;}
    vector<int>res;
    for(int i=0;i<=n-m;i++){
        if(ph==th)res.push_back(i);
        if(i<n-m)th=(th-(text[i]-'a'+1)+M)%M*131%M+(text[i+m]-'a'+1)*pw%M;
    }
    return res;
}

