vector<int> computeLPS(string p){
    int m=p.size();
    vector<int>lps(m,0);
    int len=0,i=1;
    while(i<m){
        if(p[i]==p[len]){len++;lps[i]=len;i++;}
        else{if(len)len=lps[len-1];else{lps[i]=0;i++;}}
    }
    return lps;
}
vector<int> kmpSearch(string text,string pattern){
    auto lps=computeLPS(pattern);
    vector<int>res;int i=0,j=0;
    while(i<text.size()){
        if(text[i]==pattern[j]){i++;j++;}
        if(j==pattern.size()){res.push_back(i-j);j=lps[j-1];}
        else if(i<text.size()&&text[i]!=pattern[j]){
            if(j)j=lps[j-1];else i++;
        }
    }
    return res;
}

string shortestPalindrome(string s){
    string rev=s;reverse(rev.begin(),rev.end());
    string combined=s+"#"+rev;
    auto lps=computeLPS(combined);
    int longest=lps.back();
    string suffix=s.substr(longest);
    reverse(suffix.begin(),suffix.end());
    return suffix+s;
}

